//! Minimal ACP agent skeleton.
//!
//! Speaks JSON-RPC 2.0 over a single WebSocket on 127.0.0.1.
//! Intended to be fronted by Cloudflare Tunnel (or similar reverse tunnel).
//! Implements just enough of the ACP surface to hold a conversation:
//!   initialize, session/new, session/prompt (mock streaming), session/cancel.

use std::net::SocketAddr;
use std::sync::atomic::{AtomicU64, Ordering};
use std::sync::Arc;

use axum::{
    extract::{
        ws::{Message, WebSocket, WebSocketUpgrade},
        State
    },
    response::Response,
    routing::get,
    Router
};
use serde::Deserialize;
use serde_json::{json, Value};
use tokio::net::TcpListener;

const PROTOCOL_VERSION: u32 = 1;
const BIND_ADDR: &str = "127.0.0.1:7842";

#[derive(Clone, Default)]
struct AppState {
    session_counter: Arc<AtomicU64>
}

#[derive(Debug, Deserialize)]
struct JsonRpcRequest {
    id: Option<Value>,
    method: String,
    #[serde(default)]
    params: Value
}

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    let app = Router::new()
        .route("/acp", get(acp_upgrade))
        .with_state(AppState::default());

    let addr: SocketAddr = BIND_ADDR.parse()?;
    let listener = TcpListener::bind(addr).await?;
    eprintln!("racp listening on ws://{addr}/acp");

    axum::serve(listener, app).await?;
    Ok(())
}

async fn acp_upgrade(ws: WebSocketUpgrade, State(state): State<AppState>) -> Response {
    ws.on_upgrade(move |socket| handle_session(socket, state))
}

async fn handle_session(mut socket: WebSocket, state: AppState) {
    while let Some(Ok(msg)) = socket.recv().await {
        let text = match msg {
            Message::Text(t) => t,
            Message::Close(_) => break,
            _ => continue
        };

        let req: JsonRpcRequest = match serde_json::from_str(&text) {
            Ok(r) => r,
            Err(e) => {
                eprintln!("invalid json-rpc: {e}");
                continue;
            }
        };

        if let Err(e) = dispatch(&mut socket, &state, req).await {
            eprintln!("dispatch error: {e:?}");
            break;
        }
    }
}

async fn dispatch(socket: &mut WebSocket, state: &AppState, req: JsonRpcRequest) -> anyhow::Result<()> {
    match req.method.as_str() {
        "initialize" => {
            let result = json!({
                "protocolVersion": PROTOCOL_VERSION,
                "agentCapabilities": {
                    "promptCapabilities": {
                        "image": false,
                        "audio": false,
                        "embeddedContext": false
                    },
                    "loadSession": false
                },
                "authMethods": []
            });
            respond(socket, req.id, Ok(result)).await
        }
        "session/new" => {
            let n = state.session_counter.fetch_add(1, Ordering::Relaxed);
            let session_id = format!("sess_{n:08x}");
            respond(socket, req.id, Ok(json!({ "sessionId": session_id }))).await
        }
        "session/prompt" => {
            let session_id = req
                .params
                .get("sessionId")
                .and_then(Value::as_str)
                .unwrap_or("")
                .to_string();

            for chunk in ["Hello", " from", " RACP", "!"] {
                let notif = json!({
                    "jsonrpc": "2.0",
                    "method": "session/update",
                    "params": {
                        "sessionId": session_id,
                        "update": {
                            "sessionUpdate": "agent_message_chunk",
                            "content": { "type": "text", "text": chunk }
                        }
                    }
                });
                socket.send(Message::Text(notif.to_string())).await?;
            }

            respond(socket, req.id, Ok(json!({ "stopReason": "end_turn" }))).await
        }
        "session/cancel" => Ok(()),
        _ => {
            respond(
                socket,
                req.id,
                Err(json!({ "code": -32601, "message": "method not found" }))
            )
            .await
        }
    }
}

async fn respond(socket: &mut WebSocket, id: Option<Value>, result: Result<Value, Value>) -> anyhow::Result<()> {
    let id = id.unwrap_or(Value::Null);
    let body = match result {
        Ok(r) => json!({ "jsonrpc": "2.0", "id": id, "result": r }),
        Err(e) => json!({ "jsonrpc": "2.0", "id": id, "error": e })
    };
    socket.send(Message::Text(body.to_string())).await?;
    Ok(())
}

