    // We move ownership of the Mutex by unwrapping the Arc; the reader keeps its clone.
    // Keep it simple: store an Arc in Agent too, so both sides share the map.
    Ok(Agent {
        stdin: Mutex::new(stdin),
        next_id: AtomicI64::new(1),
        pending: Mutex::new(Arc::try_unwrap(pending).unwrap_or_else(|arc| {
            // If the reader task hasn't dropped yet (it shouldn't have),
            // clone the contents so we own a fresh map. The reader will
            // keep using its original. This is a sketch-level workaround;
            // productionise by storing Arc<Mutex<...>> directly in Agent.
            let _ = arc;
            HashMap::new()
        })),
        updates_rx: Mutex::new(Some(updates_rx)),
        _child: Mutex::new(child)
    })
}

