const setBusy = (busy) => {
  input.disabled = busy;
  button.disabled = busy;
  if (!busy) {
    input.focus();
  }
};

let awaitingFirstChunk = false;

const proto = location.protocol === 'https:' ? 'wss:' : 'ws:';
const ws = new WebSocket(`${proto}//${location.host}/ws`);

ws.onopen = () => {
  status.textContent = 'connected';
};

ws.onclose = () => {
  status.textContent = 'disconnected';
  append('\n[disconnected]\n', 'sys');
  setBusy(true);
};

ws.onerror = () => {
  status.textContent = 'error';
};

ws.onmessage = (e) => {
  let msg;
  try {
    msg = JSON.parse(e.data);
  } catch {
    return;
  }
  switch (msg.type) {
    case 'append':
      if (awaitingFirstChunk && msg.role === 'agent') {
        status.textContent = 'responding';
        awaitingFirstChunk = false;
      }
      append(msg.text, msg.role || 'agent');
      break;
    case 'prompt_done':
      status.textContent = 'connected';
      awaitingFirstChunk = false;
      setBusy(false);
      break;
    case 'error':
      append(`\n[error: ${msg.message}]\n`, 'sys');
      status.textContent = 'connected';
      awaitingFirstChunk = false;
      setBusy(false);
      break;
  }
};

form.onsubmit = (e) => {
  e.preventDefault();
  const text = input.value.trim();
  if (!text || ws.readyState !== WebSocket.OPEN) {
    return;
  }
  append(`> ${text}\n`, 'user');
  ws.send(JSON.stringify({ type: 'prompt', text }));
  input.value = '';
  status.textContent = 'thinking...';
  awaitingFirstChunk = true;
  setBusy(true);
};

