const renderPermission = (msg) => {
  const card = document.createElement('div');
  card.className = 'perm';

  const title = document.createElement('div');
  title.className = 'perm-title';
  title.textContent = `permission requested: ${msg.title || 'tool'}`;
  card.appendChild(title);

  const buttons = document.createElement('div');
  buttons.className = 'perm-buttons';
  const options = Array.isArray(msg.options) ? msg.options : [];
  for (const opt of options) {
    const b = document.createElement('button');
    b.textContent = opt.name || opt.optionId || 'option';
    const kind = (opt.kind || opt.optionId || '').toString();
    if (kind.startsWith('allow')) {
      b.classList.add('allow');
    } else if (kind.startsWith('reject')) {
      b.classList.add('reject');
    }
    b.onclick = () => {
      ws.send(JSON.stringify({ type: 'permission_response', id: msg.id, optionId: opt.optionId }));
      card.classList.add('resolved');
      const resolution = document.createElement('div');
      resolution.className = 'perm-resolution';
      resolution.textContent = `→ ${b.textContent}`;
      card.appendChild(resolution);
    };
    buttons.appendChild(b);
  }
  card.appendChild(buttons);

  log.appendChild(card);
  log.scrollTop = log.scrollHeight;
};

ws.onmessage = (e) => {
  let msg;
  try {
    msg = JSON.parse(e.data);
  } catch {
    return;
  }
  switch (msg.type) {
    case 'append':
      if (awaitingFirstChunk && msg.role === 'agent') {
        status.textContent = 'responding';
        awaitingFirstChunk = false;
      }
      append(msg.text, msg.role || 'agent');
      break;
    case 'permission_request':
      renderPermission(msg);
      break;
    case 'prompt_done':
      status.textContent = 'connected';
      awaitingFirstChunk = false;
      setBusy(false);
      break;
    case 'error':
      append(`\n[error: ${msg.message}]\n`, 'sys');
      status.textContent = 'connected';
      awaitingFirstChunk = false;
      setBusy(false);
      break;
  }
};

