const ensureNewline = () => {
  // If the most recent appended node is a text span that doesn't end in
  // a newline, insert one so the user's `> ...` always starts on a
  // fresh line. Permission cards (divs) are block-level and need no help.
  const last = log.lastChild;
  if (last instanceof HTMLSpanElement && !last.textContent.endsWith('\n')) {
    append('\n', 'sys');
  }
};

form.onsubmit = (e) => {
  e.preventDefault();
  const text = input.value.trim();
  if (!text || ws.readyState !== WebSocket.OPEN) {
    return;
  }
  ensureNewline();
  append(`> ${text}\n`, 'user');
  ws.send(JSON.stringify({ type: 'prompt', text }));
  input.value = '';
  status.textContent = 'thinking...';
  awaitingFirstChunk = true;
  setBusy(true);
};

