const tabsEl = document.getElementById('tabs');
const panesEl = document.getElementById('panes');
const newTabBtn = document.getElementById('new-tab');
const cancelBtn = document.getElementById('cancel');
const form = document.getElementById('f');
const input = document.getElementById('i');
const button = document.getElementById('b');
const statusEl = document.getElementById('status');

const sessions = [];
let activeId = null;
let nextLabel = 1;

// Persistence: per-tab { id (client-local), label, acpSessionId }.
// The acpSessionId is what racp gives back via the `ready` message
// after `session/new` or `session/load`; we send it as `?session=<id>`
// on reconnect so the agent can resume history.
const STORAGE_KEY = 'racp.v1';

const saveState = () => {
  try {
    localStorage.setItem(
      STORAGE_KEY,
      JSON.stringify({
        sessions: sessions.map((s) => ({
          id: s.id,
          label: s.label,
          acpSessionId: s.acpSessionId
        })),
        activeId,
        nextLabel
      })
    );
  } catch {
    // storage disabled or full; ignore — feature just becomes a no-op
  }
};

const loadState = () => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : null;
  } catch {
    return null;
  }
};

const currentSession = () => sessions.find((s) => s.id === activeId);

