const append = (s, text, cls) => {
  const span = document.createElement('span');
  span.className = cls || 'agent';
  span.textContent = text;
  s.logEl.appendChild(span);
  // Only auto-scroll if the user is pinned to the bottom. When they
  // scroll up to read backlog, new chunks stop forcing them back down.
  if (s.id === activeId && s.pinnedToBottom) {
    s.logEl.scrollTop = s.logEl.scrollHeight;
  }
};

const ensureNewline = (s) => {
  const last = s.logEl.lastChild;
  if (last instanceof HTMLSpanElement && !last.textContent.endsWith('\n')) {
    append(s, '\n', 'sys');
  }
};

const setBusy = (s, busy) => {
  s.busy = busy;
  if (s.id === activeId) {
    input.disabled = busy;
    button.disabled = busy;
    cancelBtn.style.display = busy ? 'inline-block' : 'none';
    if (!busy) {
      input.focus();
    }
  }
};

