const handleMessage = (s, e) => {
  let msg;
  try {
    msg = JSON.parse(e.data);
  } catch {
    return;
  }
  switch (msg.type) {
    case 'ready':
      // Server just finished `session/new` or `session/load`. Persist
      // the id for reconnect. If it was a resume the agent will replay
      // past messages right after this, so clear any stale log content.
      if (msg.resumed) {
        s.logEl.innerHTML = '';
        s.pinnedToBottom = true;
      }
      s.acpSessionId = msg.sessionId;
      saveState();
      setStatus(s, 'connected');
      break;
    case 'append':
      if (s.awaitingFirstChunk && msg.role === 'agent') {
        setStatus(s, 'responding');
        s.awaitingFirstChunk = false;
      }
      append(s, msg.text, msg.role || 'agent');
      break;
    case 'permission_request':
      renderPermission(s, msg);
      break;
    case 'prompt_done':
      setStatus(s, 'connected');
      s.awaitingFirstChunk = false;
      setBusy(s, false);
      break;
    case 'error':
      append(s, `\n[error: ${msg.message}]\n`, 'sys');
      setStatus(s, 'connected');
      s.awaitingFirstChunk = false;
      setBusy(s, false);
      break;
  }
};

