input.newStr:
const connect = (s) => {
  const proto = location.protocol === 'https:' ? 'wss:' : 'ws:';
  const url = s.acpSessionId
    ? `${proto}//${location.host}/ws?session=${encodeURIComponent(s.acpSessionId)}`
    : `${proto}//${location.host}/ws`;
  s.ws = new WebSocket(url);
  s.ws.onopen = () => {
    s.reconnectAttempt = 0;
    s.disconnectNoted = false;
    // Server still needs to send `ready`; don't flip to 'connected'
    // until then so the UI reflects the actual handshake state.
    setStatus(s, 'connecting...');
  };
  s.ws.onclose = () => {
    if (s.closing) {
      // User-initiated close: honour it, do not reconnect.
      return;
    }
    setStatus(s, 'disconnected');
    setBusy(s, true);
    // Emit the disconnect line only once per outage so backoff retries
    // do not flood the log.
    if (!s.disconnectNoted) {
      append(s, '\n[disconnected, reconnecting...]\n', 'sys');
      s.disconnectNoted = true;
    }
    // Exponential backoff capped at 30 seconds.
    const delay = Math.min(30000, 500 * Math.pow(2, s.reconnectAttempt));
    s.reconnectAttempt += 1;
    s.reconnectTimer = setTimeout(() => connect(s), delay);
  };
  s.ws.onerror = () => {
    // Let onclose drive the retry — onerror fires just before it.
  };
  s.ws.onmessage = (e) => handleMessage(s, e);
};

