input.newStr:
const renderTabs = () => {
  tabsEl.innerHTML = '';
  for (const s of sessions) {
    const tab = document.createElement('div');
    tab.className = 'tab' + (s.id === activeId ? ' active' : '');
    tab.textContent = s.label;
    tab.title = 'Click to activate, double-click to rename';
    tab.onclick = () => activate(s.id);
    // Rename via native prompt. Trivial UX, fine for v1; replace with
    // inline contenteditable if we ever want slicker.
    tab.ondblclick = (ev) => {
      ev.stopPropagation();
      const next = prompt('Rename session', s.label);
      if (next !== null && next.trim()) {
        s.label = next.trim();
        saveState();
        renderTabs();
      }
    };
    // Hide close button when there's only one tab so the UI can't
    // leave itself in an empty state.
    if (sessions.length > 1) {
      const close = document.createElement('span');
      close.className = 'close';
      close.textContent = '×';
      close.title = 'Close session';
      close.onclick = (ev) => {
        ev.stopPropagation();
        closeSession(s.id);
      };
      tab.appendChild(close);
    }
    tabsEl.appendChild(tab);
  }
};

const activate = (id) => {
  activeId = id;
  for (const s of sessions) {
    s.logEl.classList.toggle('active', s.id === id);
  }
  const s = currentSession();
  if (s) {
    statusEl.textContent = s.status;
    input.disabled = s.busy;
    button.disabled = s.busy;
    cancelBtn.style.display = s.busy ? 'inline-block' : 'none';
    if (!s.busy) {
      input.focus();
    }
  }
  renderTabs();
  saveState();
};

const closeSession = (id) => {
  const i = sessions.findIndex((s) => s.id === id);
  if (i < 0) {
    return;
  }
  const s = sessions[i];
  // Mark closing so the reconnect backoff in onclose does not retry.
  s.closing = true;
  if (s.reconnectTimer) {
    clearTimeout(s.reconnectTimer);
    s.reconnectTimer = null;
  }
  try {
    if (s.ws) {
      s.ws.close();
    }
  } catch {
    // agent already disconnected, fine
  }
  s.logEl.remove();
  sessions.splice(i, 1);
  if (sessions.length === 0) {
    newSession();
    return;
  }
  if (activeId === id) {
    activate(sessions[Math.max(0, i - 1)].id);
  } else {
    renderTabs();
  }
  saveState();
};

