input.newStr:
const closeSession = (id) => {
  const i = sessions.findIndex((s) => s.id === id);
  if (i < 0) {
    return;
  }
  const s = sessions[i];
  // Mark closing so the reconnect backoff in onclose does not retry.
  s.closing = true;
  if (s.reconnectTimer) {
    clearTimeout(s.reconnectTimer);
    s.reconnectTimer = null;
  }
  try {
    if (s.ws) {
      s.ws.close();
    }
  } catch {
    // agent already disconnected, fine
  }
  // Remember the session in history so the user can restore it later.
  // Only keep sessions that actually reached a sessionId; anything
  // that never connected is not useful to resume.
  if (s.acpSessionId) {
    closed.unshift({
      id: s.id,
      label: s.label,
      acpSessionId: s.acpSessionId,
      cwd: s.cwd,
      closedAt: Date.now()
    });
    if (closed.length > HISTORY_MAX) {
      closed.length = HISTORY_MAX;
    }
  }
  s.logEl.remove();
  sessions.splice(i, 1);
  if (sessions.length === 0) {
    newSession();
    return;
  }
  if (activeId === id) {
    activate(sessions[Math.max(0, i - 1)].id);
  } else {
    renderTabs();
  }
  saveState();
};

