// ---------- history dropdown ----------

const timeAgo = (ts) => {
  const diff = Math.max(0, Date.now() - ts);
  const s = Math.floor(diff / 1000);
  if (s < 60) {
    return 'just now';
  }
  const m = Math.floor(s / 60);
  if (m < 60) {
    return `${m} min ago`;
  }
  const h = Math.floor(m / 60);
  if (h < 24) {
    return `${h} h ago`;
  }
  const d = Math.floor(h / 24);
  return `${d} d ago`;
};

const renderHistory = () => {
  historyMenu.innerHTML = '';
  if (closed.length === 0) {
    const empty = document.createElement('div');
    empty.className = 'empty';
    empty.textContent = 'no recently closed sessions';
    historyMenu.appendChild(empty);
    return;
  }
  for (const entry of closed) {
    const row = document.createElement('div');
    row.className = 'hist-item';
    row.onclick = () => restoreFromHistory(entry.acpSessionId);

    const main = document.createElement('div');
    main.className = 'hist-main';

    const lbl = document.createElement('div');
    lbl.className = 'hist-label';
    lbl.textContent = entry.label;
    main.appendChild(lbl);

    const meta = document.createElement('div');
    meta.className = 'hist-meta';
    const cwdPart = entry.cwd ? `${entry.cwd} · ` : '';
    meta.textContent = `${cwdPart}${timeAgo(entry.closedAt)}`;
    main.appendChild(meta);

    row.appendChild(main);

    const forget = document.createElement('span');
    forget.className = 'hist-forget';
    forget.textContent = '×';
    forget.title = 'Forget';
    forget.onclick = (ev) => {
      ev.stopPropagation();
      forgetHistory(entry.acpSessionId);
    };
    row.appendChild(forget);

    historyMenu.appendChild(row);
  }
};

const restoreFromHistory = (acpSessionId) => {
  const i = closed.findIndex((e) => e.acpSessionId === acpSessionId);
  if (i < 0) {
    return;
  }
