async fn run_cloudflared(cfg: Config) -> Result<()> {
    let shared = Arc::new(cfg.clone());
    let app = Router::new()
        .route("/", get(serve_ui))
        .route("/ws", get(ws_upgrade))
        .route("/state", get(get_state).put(put_state))
        .with_state(shared);

