// State lives server-side at ~/.racp/state.json (served as GET/PUT
// /state) so every browser hitting this racp sees the same list of
// open tabs, history, and next-label counter.
const STATE_URL = '/state';

let syncTimer = null;

const scheduleSync = () => {
  // Debounce so bursts of updates (activate + ready + saveState)
  // collapse into one PUT.
  if (syncTimer) {
    clearTimeout(syncTimer);
  }
  syncTimer = setTimeout(doSync, 400);
};

const doSync = async () => {
  syncTimer = null;
  const body = {
    sessions: sessions.map((s) => ({
      id: s.id,
      label: s.label,
      acpSessionId: s.acpSessionId,
      cwd: s.cwd
    })),
    closed,
    activeId,
    nextLabel
  };
  try {
    await fetch(STATE_URL, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(body)
    });
  } catch {
    // Server unreachable: state stays local until next successful
    // sync. If racp itself is down, the WS is dead too and nothing
    // works, so this is only a concern during brief blips.
  }
};

const fetchState = async () => {
  try {
    const res = await fetch(STATE_URL);
    if (!res.ok) {
      return null;
    }
    return await res.json();
  } catch {
    return null;
  }
};

