// Startup: fetch state from the server and rehydrate. Falls back to a
// fresh session if the server returns nothing (first run) or is
// unreachable.
const init = async () => {
  const saved = await fetchState();
  if (saved && Array.isArray(saved.closed)) {
    for (const entry of saved.closed.slice(0, HISTORY_MAX)) {
      closed.push(entry);
    }
  }
  if (saved && Array.isArray(saved.sessions) && saved.sessions.length > 0) {
    nextLabel = saved.nextLabel || saved.sessions.length + 1;
    for (const entry of saved.sessions) {
      restoreSession(entry);
    }
    const restoreActive =
      saved.activeId && sessions.some((s) => s.id === saved.activeId)
        ? saved.activeId
        : sessions[0].id;
    activate(restoreActive);
  } else {
    newSession();
  }
};

init();

