const renderTabs = () => {
  tabsEl.innerHTML = '';
  for (const s of sessions) {
    const tab = document.createElement('div');
    tab.className = 'tab' + (s.id === activeId ? ' active' : '');
    tab.textContent = s.label;
    tab.title = s.cwd
      ? `${s.label} · ${s.cwd}\nClick to activate, double-click to rename`
      : 'Click to activate, double-click to rename';
    tab.onclick = () => activate(s.id);
    tab.ondblclick = (ev) => {
      ev.stopPropagation();
      const next = prompt('Rename session', s.label);
      if (next !== null && next.trim()) {
        s.label = next.trim();
        scheduleSync();
        renderTabs();
      }
    };

    // Attention dot (background tabs only; cleared on activate).
    if (s.attention && s.id !== activeId) {
      const dot = document.createElement('span');
      dot.className = `dot dot-${s.attention}`;
      tab.appendChild(dot);
    }

    // Close button is always present. If it happens to be the last
    // tab, closeSession auto-spawns a fresh default session so the UI
    // never ends up empty.
    const close = document.createElement('span');
    close.className = 'close';
    close.textContent = '×';
    close.title = 'Close session';
    close.onclick = (ev) => {
      ev.stopPropagation();
      closeSession(s.id);
    };
    tab.appendChild(close);
    tabsEl.appendChild(tab);
  }
};

const activate = (id) => {
  activeId = id;
  for (const s of sessions) {
    s.logEl.classList.toggle('active', s.id === id);
  }
  const s = currentSession();
  if (s) {
    // Becoming active clears any attention marker — the user is
    // looking at this tab now.
    if (s.attention) {
      s.attention = null;
    }
    statusEl.textContent = s.status;
    input.disabled = s.busy;
    button.disabled = s.busy;
    cancelBtn.style.display = s.busy ? 'inline-block' : 'none';
    if (!s.busy) {
      input.focus();
    }
  }
  renderTabs();
  scheduleSync();
};

