input.newStr:
s.ws.onclose = () => {
  if (s.closing) {
    // User-initiated close: honour it, do not reconnect.
    return;
  }
  // Connection status lives in the header; no log spam.
  setStatus(s, 'reconnecting...');
  setBusy(s, true);
  // Exponential backoff capped at 30 seconds.
  const delay = Math.min(30000, 500 * Math.pow(2, s.reconnectAttempt));
  s.reconnectAttempt += 1;
  s.reconnectTimer = setTimeout(() => connect(s), delay);
};

