input.newStr:
const attachLog = (s) => {
  s.logEl = document.createElement("div");
  s.logEl.className = "log";
  // Sticky per-session status banner. Lives inside the pane so each
  // tab shows its own connection/turn state independently.
  s.statusEl = document.createElement("div");
  s.statusEl.className = "log-status";
  s.statusEl.textContent = s.status;
  s.statusEl.setAttribute("data-state", s.status);
  s.logEl.appendChild(s.statusEl);
  panesEl.appendChild(s.logEl);
  // Scroll pinning: whenever the log scrolls, remember whether the
  // user is near the bottom. `append` and `renderPermission` consult
  // this flag before forcing scrollTop.
  s.logEl.addEventListener("scroll", () => {
    const el = s.logEl;
    s.pinnedToBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 20;
  });
};

