const makeSessionState = (id, label, acpSessionId, cwd) => ({
  id,
  label,
  acpSessionId: acpSessionId || null,
  cwd: cwd || null,
  // A session is "used" once it's had at least one prompt. Kiro only
  // writes a session to disk on first prompt, so unused sessions
  // can't be resumed via `session/load`. We avoid persisting the
  // acpSessionId for such sessions so reloads don't produce noisy
  // session/load failures.
  used: !!acpSessionId,
  logEl: null,
  ws: null,
  busy: false,
  awaitingFirstChunk: false,
  status: "connecting...",
  closing: false,
  reconnectAttempt: 0,
  reconnectTimer: null,
  pinnedToBottom: true,
  // Tab attention marker shown as a coloured dot when this session is
  // not the active tab: 'done' | 'permission' | 'error' | null.
  // Cleared when the user activates the tab.
  attention: null,
});

